const FIRST_INSURANCE_NUMERATOR = 11;
const FIRST_INSURANCE_DENOMINATOR = 10;
const PROCESSING_FEE = 5;

const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune"]);

const componentBasePremium = (count: number): number => {
  const blocks = Math.floor(count / BLOCK_SIZE);
  const loose = count % BLOCK_SIZE;
  return blocks * BLOCK_PREMIUM + loose * COMPONENT_PREMIUM;
};

const basePremium = (items: Item[]): number => {
  const componentCount = items.filter((item) => COMPONENT_TYPES.has(item.type)).length;
  const mainTotal = items
    .filter((item) => !COMPONENT_TYPES.has(item.type))
    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  return mainTotal + componentBasePremium(componentCount);
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => {
    const base = basePremium(step.items);
    const withFirstInsurance =
      (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
    const premium = Math.ceil(withFirstInsurance + PROCESSING_FEE);
    return { premium };
  });
