import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Base premiums for single main items (base + 5 fee, first-quote: +10% first insurance) ---
  // Use simplest quote path. The very first quote in a scenario has no follow-up discount.
  it("empty item list → premium 5 G (only the processing fee)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [] }],
    });
    expect(result).toEqual({ results: [{ premium: 5 }] });
  });
  it("single sword (base 100) newcomer 0yr → 100 + 10 first = 110 + 5 fee = 115 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "sword" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 115 }] });
  });
  it("single amulet (base 60) newcomer 0yr → 60 + 6 first = 66 + 5 fee = 71 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "amulet" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it("single staff (base 80) newcomer 0yr → 80 + 8 first = 88 + 5 fee = 93 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "staff" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 93 }] });
  });
  it("single potion (base 40) newcomer 0yr → 40 + 4 first = 44 + 5 fee = 49 G", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "potion" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 49 }] });
  });

  // --- Components and building blocks (base premium examples, then wrapped through modifiers) ---
  it("single rune (base 25) newcomer 0yr → 25 + 2.5 first = 27.5 + 5 fee = 33 G (round up)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 33 }] });
  });
  it("2 runes → 50 G base premium (no block)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
    });
    expect(result).toEqual({ results: [{ premium: 60 }] });
  });
  it("3 runes → 60 G base premium (block applies)", () => {
    const result = runScenario({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        { op: "quote", items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }] },
      ],
    });
    expect(result).toEqual({ results: [{ premium: 71 }] });
  });
  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
  it.todo("7 runes → 175 G base premium (one block of 3 @60 + 4 @25)");

  // --- "Alike" components: same type only ---
  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");

  // --- Item-specific modifiers in isolation ---
  it.todo("cursed sword adds 50% of its base premium (curse surcharge = 50 G on a 100 G sword)");
  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies (+30%)");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");

  // --- Modifier scope on multi-item policies ---
  it.todo("cursed sword (100) + plain amulet (60) → policy base 160; curse adds 50 (of sword) → 210 before policy modifiers and fee");

  // --- Policy-wide modifiers ---
  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
  it.todo("first insurance carries 10% surcharge on the policy base premium");
  it.todo("second quote in scenario gets 15% follow-up discount");
  it.todo("first insurance applies per item per quote regardless of customer history");

  // --- Rounding ---
  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");

  // --- Integration examples ---
  it.todo("newcomer cursed sword (steel, ench 3), 0yr → 165 G (100 + 50 curse + 10 first + 5 fee)");
  it.todo("long-standing 3yr 2nd quote, cursed sword (steel, ench 7) → 160 G (100 + 50 + 30 − 20 loyalty + 10 first − 15 follow-up + 5 fee)");

  // --- Claim: standard reimbursement (no special clauses) ---
  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (500 − 100 deductible)");
  it.todo("damage to a rune (value 250), damage 200 → payout 100 (200 − 100 deductible)");

  // --- Claim: enchantment / dragon clauses ---
  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (50% rule wins: 500 − 100)");
  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full: 800 − 100)");
  it.todo("steel sword, ench 9, damage 1000 → payout 400 (50% then deductible: 500 − 100)");
  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");

  // --- Claim: cap ---
  it.todo("policy of sword + amulet → insurance sum 1600, cap 3200");
  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
  it.todo("policy of sword + 3 runes → insurance sum 1750 (block discount does not affect sum)");
  it.todo("two swords → insurance sum 2000, cap 4000");
  it.todo("cap exhaustion: first claim 1500 → payout 1400 remainingCap 600; second claim 1500 → payout 600 remainingCap 0");

  // --- Claim: payout rounding ---
  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");

  // --- Multiple items of same type ---
  it.todo("two swords, dragon attack damages both → each sword damage entry is a separate deductible");
  it.todo("more damage entries of a type than the policy covers → claim rejected (non-zero exit)");

  // --- Error cases ---
  it.todo("quote with unknown item type (broomstick) → error (non-zero exit, stderr, no results)");
  it.todo("claim references item not in policy (amulet damaged, only sword insured) → error");
  it.todo("claim references unknown item type → error");
  it.todo("claim with damage amount -200 → error");

  // --- CLI end-to-end via runScenario ---
  it.todo("scenario with a quote then a claim returns results in same order");
});

