interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

type Step = QuoteStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const FIRST_INSURANCE_NUMERATOR = 11;
const FIRST_INSURANCE_DENOMINATOR = 10;
const PROCESSING_FEE = 5;

const COMPONENT_PREMIUM = 25;
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const componentBasePremium = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const countByType = (items: Item[]): Map<string, number> =>
  items.reduce(
    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
    new Map<string, number>(),
  );

const componentTotal = (items: Item[]): number =>
  [...countByType(items.filter(isComponent)).values()].reduce(
    (sum, count) => sum + componentBasePremium(count),
    0,
  );

const basePremium = (items: Item[]): number => {
  const mainTotal = items
    .filter((item) => !isComponent(item))
    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
  return mainTotal + componentTotal(items);
};

const quotePremium = (items: Item[]): number => {
  const base = basePremium(items);
  const withFirstInsurance =
    (base * FIRST_INSURANCE_NUMERATOR) / FIRST_INSURANCE_DENOMINATOR;
  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
};

export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const results = scenario.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};

