const insuranceSum = (items: Item[]): number =>
  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);

const damagePayout = (damage: Damage): number =>
  Math.max(damage.amount - DEDUCTIBLE, 0);

const processClaim = (policy: Policy, claim: ClaimStep): ClaimResult => {
  const payout = claim.incident.damages.reduce(
    (sum, damage) => sum + damagePayout(damage),
    0,
  );
  policy.remainingCap -= payout;
  return { payout, remainingCap: policy.remainingCap };
};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const years = scenario.customer.yearsWithMHPCO;
  const policies: Policy[] = [];
  let quoteCount = 0;
  const results = scenario.steps.map((step): StepResult => {
    if (step.op === "quote") {
      const premium = quotePremium(step.items, years, quoteCount > 0);
      quoteCount += 1;
      policies[scenario.steps.indexOf(step)] = {
        items: step.items,
        remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
      };
      return { premium };
    }
    return processClaim(policies[step.policy], step);
  });
  return { results };
};

